function normalizeBaseUrl(value) {
  const rawValue = String(value || "").trim() || DEFAULT_BASE_URL;
  let url;
  try {
    url = new URL(rawValue);
  } catch {
    throw new Error("服务地址不是有效 URL");
  }
  if (url.protocol !== "http:" && url.protocol !== "https:") throw new Error("服务地址只支持 http:// 或 https://");
  url.hash = "";
  url.search = "";
  url.pathname = url.pathname.replace(/\/+$/, "");
  return url.toString().replace(/\/$/, "");
}

function apiUrl(baseUrl, path) {
  const normalizedBaseUrl = normalizeBaseUrl(baseUrl);
  const normalizedPath = String(path || "").startsWith("/") ? path : `/${path || ""}`;
  return `${normalizedBaseUrl}${normalizedPath}`;
}

function isLoopbackHost(hostname) {
  const value = String(hostname || "").toLowerCase();
  return value === "localhost" || value === "127.0.0.1" || value === "::1" || value === "[::1]";
}

function isDefaultBaseUrl(baseUrl) {
  return normalizeBaseUrl(baseUrl) === DEFAULT_BASE_URL;
}

function permissionOriginPattern(baseUrl) {
  const url = new URL(normalizeBaseUrl(baseUrl));
  return `${url.protocol}//${url.hostname}/*`;
}

function shouldWarnAboutBaseUrl(baseUrl) {
  const url = new URL(normalizeBaseUrl(baseUrl));
  return !isLoopbackHost(url.hostname);
}

function formatTime(value) {
  if (!value) return "—";
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "—";
  return date.toLocaleTimeString();
}

function truncate(value, maxLength = 80) {
  const text = String(value || "").trim();
  if (!text) return "—";
  return text.length > maxLength ? `${text.slice(0, maxLength - 1)}…` : text;
}

function shortSessionId(value) {
